#include <ctype.h>
#include <errno.h>
#include <stdio.h>
#include <stdlib.h>

int main(void) {
    char line[64];
    if (fgets(line, sizeof line, stdin) == NULL) return 1;
    errno = 0;
    char *end;
    long value = strtol(line, &end, 10);
    while (isspace((unsigned char)*end)) ++end;
    if (errno != 0 || end == line || *end != '\0' || value < 0 || value > 100) puts("invalid");
    else printf("%ld\n", value);
    return 0;
}
